{"path": "/tmp/fun4me-store/src/lib/store/cart.ts", "content": "import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export interface CartItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
  image_url?: string;
  max_stock?: number;
}

interface CartState {
  items: CartItem[];
  addItem: (item: Omit<CartItem, 'quantity'>) => void;
  removeItem: (id: string) => void;
  updateQuantity: (id: string, quantity: number) => void;
  clearCart: () => void;
  totalItems: () => number;
  totalPrice: () => number;
}

export const useCartStore = create<CartState>()(
  persist(
    (set, get) => ({
      items: [],

      addItem: (item) => {
        set((state) => {
          const existingItem = state.items.find((i) => i.id === item.id);
          if (existingItem) {
            return {
              items: state.items.map((i) =>
                i.id === item.id
                  ? {
                      ...i,
                      quantity: Math.min(
                        i.quantity + 1,
                        i.max_stock ?? Infinity,
                      ),
                    }
                  : i,
              ),
            };
          }
          return { items: [...state.items, { ...item, quantity: 1 }] };
        });
      },

      removeItem: (id) => {
        set((state) => ({
          items: state.items.filter((i) => i.id !== id),
        }));
      },

      updateQuantity: (id, quantity) => {
        set((state) => ({
          items:
            quantity <= 0
              ? state.items.filter((i) => i.id !== id)
              : state.items.map((i) => (i.id === id ? { ...i, quantity } : i)),
        }));
      },

      clearCart: () => set({ items: [] }),

      totalItems: () => {
        return get().items.reduce((total, item) => total + item.quantity, 0);
      },

      totalPrice: () => {
        return get().items.reduce(
          (total, item) => total + item.price * item.quantity,
          0,
        );
      },
    }),
    {
      name: 'fun4me-cart',
    },
  ),
);
"}

{"path": "/tmp/fun4me-store/src/lib/utils/format.ts", "content": "import { CURRENCY } from '@/lib/constants';

/**
 * Formats a number as Paraguayan Guaraníes (₲)
 * Guaraníes don't use decimal places
 *
 * @example formatPrice(150000) => "₲ 150.000"
 * @example formatPrice(1500000) => "₲ 1.500.000"
 */
export function formatPrice(amount: number): string {
  const formatted = new Intl.NumberFormat('es-PY', {
    style: 'decimal',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);

  return `${CURRENCY.symbol} ${formatted}`;
}

/**
 * Formats a number as compact Guaraníes for display
 *
 * @example formatPriceCompact(1500000) => "₲ 1,5M"
 */
export function formatPriceCompact(amount: number): string {
  if (amount >= 1_000_000) {
    const millions = amount / 1_000_000;
    return `${CURRENCY.symbol} ${millions.toFixed(1).replace('.', ',')}M`;
  }
  if (amount >= 1_000) {
    const thousands = amount / 1_000;
    return `${CURRENCY.symbol} ${thousands.toFixed(0)}K`;
  }
  return formatPrice(amount);
}

/**
 * Parse a price string back to number
 */
export function parsePrice(priceString: string): number {
  const cleaned = priceString.replace(/[^\d]/g, '');
  return parseInt(cleaned, 10) || 0;
}
"}

{"path": "/tmp/fun4me-store/src/lib/utils/whatsapp.ts", "content": "import { WHATSAPP_NUMBER } from '@/lib/constants';
import type { CartItem } from '@/lib/store/cart';
import { formatPrice } from '@/lib/utils/format';

/**
 * Generates a WhatsApp link with a pre-filled message
 */
export function generateWhatsAppLink(message: string): string {
  const encodedMessage = encodeURIComponent(message);
  const cleanNumber = WHATSAPP_NUMBER.replace(/[^0-9]/g, '');
  return `https://wa.me/${cleanNumber}?text=${encodedMessage}`;
}

/**
 * Generates a WhatsApp order message from cart items
 */
export function generateOrderMessage(
  items: CartItem[],
  customerName?: string,
): string {
  const header = '🛒 *Nuevo Pedido - Fun4Me Store*\n\n';
  const customerLine = customerName ? `👤 *Cliente:* ${customerName}\n\n` : '';

  const itemLines = items
    .map(
      (item, index) =>
        `${index + 1}. ${item.name}\n   Cantidad: ${item.quantity} | Precio: ${formatPrice(item.price * item.quantity)}`,
    )
    .join('\n\n');

  const total = items.reduce(
    (sum, item) => sum + item.price * item.quantity,
    0,
  );
  const totalLine = `\n\n💰 *Total: ${formatPrice(total)}*`;

  return `${header}${customerLine}${itemLines}${totalLine}`;
}

/**
 * Generates a WhatsApp link for placing an order
 */
export function generateOrderWhatsAppLink(
  items: CartItem[],
  customerName?: string,
): string {
  const message = generateOrderMessage(items, customerName);
  return generateWhatsAppLink(message);
}
"}

